classDiagram
  class StateChapter
  class DistrictChapter
  class Member {
    +status : MemberStatus
  }
  class MembershipApplication {
    +status : ApplicationStatus
  }
  class NotificationContract
  class Committee
  class Mandate {
    +termOfOffice
  }
  class Campaign
  class Deployment {
    +hours
  }
  class Payment {
    +amount
    +date
  }
  class MembershipFeePayment {
    +contributionYear
  }
  class Donation

  StateChapter "1" *-- "0..*" DistrictChapter : district chapters
  DistrictChapter "1" -- "0..*" Member : members
  DistrictChapter "1" -- "0..*" MembershipApplication : receives
  MembershipApplication "1" -- "1" Member : emerges
  Member ..|> NotificationContract : implements
  Committee "1" *-- "0..*" Mandate : awards
  Mandate "1" -- "1" Member : holder
  DistrictChapter "1" o-- "0..*" Campaign : runs
  Campaign "1" -- "0..*" Deployment : deployments
  Member "1" -- "0..*" Deployment : participates
  Payment <|-- MembershipFeePayment
  Payment <|-- Donation
  Donation "0..*" -- "0..1" Campaign : earmarked for
  Member "1" -- "0..*" Payment : originates

